 2	import { Tooltip, TooltipPosition } from '@patternfly/react-core';
 3	import { PlusIcon } from '@patternfly/react-icons/dist/esm/icons/plus-icon';
 4	import { BUILDER_NODE_ADD_RADIUS } from './const';
 5	
 6	import './PlusNodeDecorator.scss';
 7	
 8	type PlusNodeProps = {
 9	  x: number;
10	  y: number;
11	  tooltip: string;
12	  tooltipPosition?: TooltipPosition;
13	  onClick?: () => void;
14	};
15	
16	const PlusNodeDecorator: React.FC<PlusNodeProps> = ({
17	  x,
18	  y,
19	  onClick,
20	  tooltip,
21	  tooltipPosition,
22	}) => {
23	  const iconRef = React.useRef();
24	  return (
25	    <Tooltip triggerRef={iconRef} content={tooltip} position={tooltipPosition}>
26	      <g
27	        className="odc-plus-node-decorator"
