30	        ref={iconRef}
31	      >
32	        <circle
33	          cx={0}
34	          cy={0}
35	          r={BUILDER_NODE_ADD_RADIUS}
36	          className="odc-plus-node-decorator__circle"
37	        />
38	        <g transform="translate(-6, -6)">
39	          <PlusIcon color="white" />
40	        </g>
41	      </g>
42	    </Tooltip>
43	  );
44	};
45	
